"use client";

import { useEffect, useState } from "react";
import { useRouter, useParams } from "next/navigation";
import { toast } from "sonner";
import { Loader2, ArrowLeft, Pencil, Calendar, Clock, FolderTree } from "lucide-react";
import { PageSection } from "@ui/components/layout";
import { Button } from "@ui/components/button";
import { Card, CardContent, CardHeader, CardTitle } from "@ui/components/card";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";
import { unwrapEnvelope, formatDateTime } from "../_component";
import { TypographyH1 } from "@ui/components/typography";
import { ADMIN_PAGE_TITLE_PRIMARY_CLASS } from "@ui/lib/layout-shell";
import { resolveCategoryIcon } from "@/lib/category-icons";
import type { CategoryRow } from "../_component/types";

function CategoryDetailInner() {
  const router = useRouter();
  const params = useParams();
  const categoryId = params.id as string;
  const [loading, setLoading] = useState(true);
  const [category, setCategory] = useState<CategoryRow | null>(null);

  useEffect(() => {
    let cancelled = false;
    async function loadCategory() {
      try {
        setLoading(true);
        const detail = unwrapEnvelope<CategoryRow>(
          await api.http.get(`/admin/categories/${categoryId}`),
        );
        if (!cancelled) setCategory(detail);
      } catch {
        if (!cancelled) {
          toast.error("Không tải được danh mục");
          router.push("/categories");
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }
    void loadCategory();
    return () => { cancelled = true; };
  }, [categoryId, router]);

  if (loading) {
    return (
      <PageSection max="full" className="min-w-0 flex items-center justify-center py-24">
        <Loader2 className="size-8 animate-spin text-muted-foreground" />
      </PageSection>
    );
  }

  if (!category) return null;

  const IconComponent = category.icon ? resolveCategoryIcon(category.icon) : null;

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="flex items-center gap-3">
          <Button
            type="button"
            variant="ghost"
            size="sm"
            className="gap-1 px-2"
            onClick={() => router.push("/categories")}
          >
            <ArrowLeft className="size-4" />
            Quay lại
          </Button>
          <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
            {category.name}
          </TypographyH1>
        </div>
        <Button
          type="button"
          variant="default"
          className="gap-2 rounded-lg px-5 font-semibold"
          onClick={() => router.push(`/categories/${categoryId}/edit`)}
        >
          <Pencil className="size-4" />
          Chỉnh sửa
        </Button>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        <div className="space-y-6 lg:col-span-2">
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Thông tin danh mục</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center gap-3">
                {IconComponent && <IconComponent className="size-8 text-primary" />}
                <div>
                  <p className="text-sm text-muted-foreground">Tên hiển thị</p>
                  <p className="font-medium">{category.name}</p>
                </div>
              </div>
              <div>
                <p className="text-sm text-muted-foreground">Slug</p>
