import type {
  ApiEnvelope,
  CategoryTreeOption,
  PagedApiShape,
  PagedResult,
} from "./types";

export function slugify(input: string): string {
  return input
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export function buildCategoryOptionTree(
  rows: CategoryTreeOption[]
): CategoryTreeOption[] {
  const byId = new Map<string, CategoryTreeOption>();

  for (const row of rows) {
    byId.set(row.id, {
      ...row,
      subRows: [],
    });
  }

  const roots: CategoryTreeOption[] = [];
  for (const row of byId.values()) {
    const parentId = row.parentId ?? null;
    if (parentId && byId.has(parentId)) {
      byId.get(parentId)?.subRows?.push(row);
      continue;
    }
    roots.push(row);
  }

  const sortTree = (items: CategoryTreeOption[]): CategoryTreeOption[] =>
    [...items]
      .sort((a, b) => {
        const sortDelta = (a.sortOrder ?? 0) - (b.sortOrder ?? 0);
        if (sortDelta !== 0) return sortDelta;
        return a.name.localeCompare(b.name, "vi");
      })
      .map((item) => ({
        ...item,
        subRows: sortTree(item.subRows ?? []),
      }));

  return sortTree(roots);
}

export function unwrapEnvelope<T>(payload: unknown): T {
  if (!payload || typeof payload !== "object") return payload as T;
  const envelope = payload as ApiEnvelope<T>;
  if (envelope.success === false) {
    throw new Error(envelope.message || envelope.error || "Yeu cau that bai");
  }
  return "data" in envelope ? (envelope.data as T) : (payload as T);
}

export function normalizePaged<T>(payload: unknown): PagedResult<T> {
  const data = unwrapEnvelope<PagedApiShape<T> | T[]>(payload);
  if (Array.isArray(data)) {
    return { items: data, total: data.length };
  }
  return {
    items: data.data ?? [],
    total: data.pagination?.total ?? data.data?.length ?? 0,
  };
}

export function buildCategoriesFilterQuery(
  filters: { id: string; value: unknown }[]
): Record<string, string> {
  const query: Record<string, string> = {};
  for (const filter of filters) {
    const { value } = filter;
    if (value === undefined || value === null || value === "") continue;

    if (filter.id === "parentId") {
      if (Array.isArray(value)) {
        const vals = value.map((v) => String(v)).filter(Boolean);
        if (vals.length) query.parentId = vals.join(",");
      } else if (typeof value === "string" && value.includes(",")) {
        const vals = value.split(",").map((v) => v.trim()).filter(Boolean);
        if (vals.length) query.parentId = vals.join(",");
      } else {
        const v = String(value).trim();
        if (v) query.parentId = v;
      }
    }
  }
  return query;
}

export function formatDateTime(value: string): string {
  if (!value) return "";
  try {
    const date = new Date(value);
    if (!isNaN(date.getTime())) {
      const day = String(date.getDate()).padStart(2, "0");
      const month = String(date.getMonth() + 1).padStart(2, "0");
      const year = date.getFullYear();
      const hours = String(date.getHours()).padStart(2, "0");
      const minutes = String(date.getMinutes()).padStart(2, "0");
      return `${day}/${month}/${year} ${hours}:${minutes}`;
    }
  } catch {
    // Ignore
  }
  return "";
}

src/app/categories/_component/_alert-dia.content:
"use client";

import { Archive, ArchiveRestore, Trash2 } from "lucide-react";
import { AdminConfirmActionDialog } from "@/components/admin-confirm-action-dialog";
import type { CategoryConfirmAction } from "../types";

export interface CategoriesConfirmDialogProps {
  confirmAction: CategoryConfirmAction | null;
  deleteMutation: {
    isPending: boolean;
  };
  restoreMutation: {
    isPending: boolean;
  };
  purgeMutation: {
    isPending: boolean;
  };
  onOpenChange: (open: boolean) => void;
  onConfirm: () => void;
  contentClassName?: string;
}

export function CategoriesConfirmDialog({
  confirmAction,
  deleteMutation,
  restoreMutation,
  purgeMutation,
  onOpenChange,
  onConfirm,
  contentClassName,
}: CategoriesConfirmDialogProps) {
  if (!confirmAction) return null;

  const { kind, row } = confirmAction;

  return (
    <AdminConfirmActionDialog
      open={true}
      onOpenChange={onOpenChange}
      contentClassName={contentClassName}
      footerClassName="gap-2"
      icon={
        kind === "delete" ? (
          <Archive className="size-5 shrink-0 text-destructive" />
        ) : kind === "restore" ? (
          <ArchiveRestore className="size-5 shrink-0 text-primary" />
        ) : kind === "purge" ? (
          <Trash2 className="size-5 shrink-0 text-destructive" />
        ) : null
      }
      title={
        kind === "delete"
          ? "Đưa danh mục vào thùng rác?"
          : kind === "restore"
            ? "Khôi phục danh mục?"
            : kind === "purge"
              ? "Xóa vĩnh viễn danh mục?"
              : ""
      }
      description={
        kind === "delete"
          ? `«${row.name}» (slug \`${row.slug}\`) sẽ ẩn khỏi hệ thống cho đến khi khôi phục.`
          : kind === "restore"
            ? `Đưa «${row.name}» trở lại danh sách đang hoạt động.`
            : kind === "purge"
              ? `«${row.name}» (slug \`${row.slug}\`) sẽ bị xoá khỏi cơ sở dữ liệu. Không thể hoàn tác.`
              : null
      }
      confirmLabel={
        kind === "delete"
          ? "Xóa tạm"
          : kind === "restore"
            ? "Khôi phục"
            : kind === "purge"
              ? "Xóa vĩnh viễn"
              : "Xác nhận"
      }
      confirmDestructive={kind === "delete" || kind === "purge"}
      confirmDisabled={
        deleteMutation.isPending || restoreMutation.isPending || purgeMutation.isPending
      }
      confirmLoading={
        kind === "delete"
          ? deleteMutation.isPending
          : kind === "restore"
            ? restoreMutation.isPending
            : kind === "purge"
              ? purgeMutation.isPending
              : false
      }
      onConfirm={() => {
        void onConfirm();
      }}
    />
  );
}

src/app/categories/_component/_dialog/ca.content:
"use client";

import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@ui/components/dialog";
import { Button } from "@ui/components/button";
import { Input } from "@ui/components/input";
import { Textarea } from "@ui/components/textarea";
import { FieldError } from "@ui/components/field";
import { FormFieldCol } from "@ui/components/typing";
import { SelectPicker, TreePicker, type TreeOption, type SelectPickerOption } from "@ui/components/pickers";
import { Plus } from "lucide-react";
import { Controller, type UseFormReturn } from "react-hook-form";
import type { CategoryTreeOption } from "../types";
import { CATEGORY_ICON_OPTIONS, resolveCategoryIcon } from "@/lib/category-icons";
import { cn } from "@ui/lib/utils";
import { ADMIN_DIALOG_CONTENT_CATEGORY_CLASS } from "@ui/lib/layout-shell";
import type { CategoryFormValues } from "../_hooks";

const ROOT_PARENT_VALUE = "__root__";

function buildParentTreeOptions(
  rows: CategoryTreeOption[],
  excludedIds: Set<string>,
): TreeOption[] {
  const result: TreeOption[] = [];
  for (const row of rows) {
    if (excludedIds.has(row.id)) continue;
    const children = row.subRows
      ? buildParentTreeOptions(row.subRows, excludedIds)
      : [];
    result.push({
      value: row.id,
      label: row.name,
      children: children.length > 0 ? children : undefined,
    });
  }
  return result;
}

const ICON_OPTIONS: SelectPickerOption[] = CATEGORY_ICON_OPTIONS.map((name) => {
  const Icon = resolveCategoryIcon(name);
  return {
    value: name,
    label: name,
    render: () => (
      <div className="flex items-center gap-2">
        <Icon className="size-4" />
        <span>{name}</span>
      </div>
    ),
  };
});

export interface CategoriesFormDialogProps {
  form: UseFormReturn<CategoryFormValues>;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSubmit: (values: CategoryFormValues) => void;
  submitting: boolean;
  categoryTreeOptions: CategoryTreeOption[];
  slugify: (value: string) => string;
  contentClassName?: string;
  canWriteCategories: boolean;
  editingId: string | null;
  onOpenCreate: () => void;
}

export function CategoriesFormDialog({
  form,
  open,
  onOpenChange,
  onSubmit,
  submitting,
  categoryTreeOptions,
  slugify,
  contentClassName,
  canWriteCategories,
  editingId,
  onOpenCreate,
}: CategoriesFormDialogProps) {
  const { control, watch } = form;
  const currentParentId = watch("parentId");

  const excludedIds = editingId ? new Set([editingId]) : new Set<string>();
  const parentTreeOptions = buildParentTreeOptions(categoryTreeOptions, excludedIds);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      {canWriteCategories && (
        <DialogTrigger
          render={
            <Button
              onClick={onOpenCreate}
              className="flex h-12 items-center gap-2 rounded-lg px-6 font-bold shadow-md"
            />
          }
        >
          <Plus className="size-5" aria-hidden /> Thêm danh mục
        </DialogTrigger>
      )}
      <DialogContent className={contentClassName ?? ADMIN_DIALOG_CONTENT_CATEGORY_CLASS}>
        <DialogHeader>
          <DialogTitle className="text-2xl font-extrabold">
            {editingId ? "Chỉnh sửa danh mục" : "Tạo danh mục mới"}
          </DialogTitle>
          <DialogDescription>
            Slug được tự động sinh từ tên. Cập nhật slug sẽ tự đồng bộ lại
            tham chiếu trên các nội dung liên quan.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <Controller
              name="name"
              control={control}
              render={({ field, fieldState }) => (
                <FormFieldCol label="Tên hiển thị" required className="sm:col-span-2">
                  <Input
                    placeholder="VD: Tin tuyển sinh"
                    {...field}
                    onChange={(e) => {
                      const { value } = e.target;
                      field.onChange(value);
                      if (!editingId) form.setValue("slug", slugify(value));
                    }}
                    className={cn(fieldState.error && "border-destructive")}
                  />
                  {fieldState.error && (
                    <FieldError>{fieldState.error.message}</FieldError>
                  )}
                </FormFieldCol>
              )}
            />

            <Controller
              name="slug"
              control={control}
              render={({ field, fieldState }) => (
                <FormFieldCol label="Slug" className="sm:col-span-2">
                  <Input
                    placeholder="tin-tuyen-sinh"
                    {...field}
                    onChange={(e) => field.onChange(slugify(e.target.value))}
                    className={cn(fieldState.error && "border-destructive")}
                  />
                  {fieldState.error && (
                    <FieldError>{fieldState.error.message}</FieldError>
                  )}
                </FormFieldCol>
              )}
            />

            <Controller
              name="icon"
              control={control}
              render={({ field }) => (
                <FormFieldCol label="Biểu tượng">
                  <SelectPicker
                    value={field.value}
                    onChange={(v) => field.onChange((v as string) ?? "Package2")}
                    options={ICON_OPTIONS}
                    placeholder="Chọn biểu tượng"
                  />
                </FormFieldCol>
              )}
            />

            <Controller
              name="sortOrder"
              control={control}
              render={({ field }) => (
                <FormFieldCol label="Thứ tự">
                  <Input
                    type="number"
                    {...field}
                    onChange={(e) => field.onChange(Number(e.target.value) || 0)}
                  />
                </FormFieldCol>
              )}
            />

            <Controller
              name="description"
              control={control}
              render={({ field }) => (
                <FormFieldCol label="Mô tả" className="sm:col-span-2">
                  <Textarea
                    placeholder="Mô tả ngắn gọn"
                    {...field}
                    rows={2}
                  />
                </FormFieldCol>
              )}
            />

            <Controller
              name="parentId"
              control={control}
              render={({ field }) => (
                <FormFieldCol label="Danh mục cha" className="sm:col-span-2">
                  <TreePicker
                    value={currentParentId === ROOT_PARENT_VALUE ? "" : currentParentId}
                    onChange={(value) =>
                      field.onChange((typeof value === "string" && value) || ROOT_PARENT_VALUE)
                    }
                    options={parentTreeOptions}
                    placeholder="Cấp gốc"
                  />
                </FormFieldCol>
              )}
            />
          </div>

          <DialogFooter className="flex justify-between items-center">
            <Button
              type="button"
              variant="outline"
              className="mr-auto rounded-lg"
              onClick={() => onOpenChange(false)}
              disabled={submitting}
            >
              Hủy
            </Button>
            <Button
              type="submit"
              className="rounded-lg font-bold"
              disabled={submitting}
            >
              {submitting ? "Đang lưu..." : "Lưu"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

