"use client"

import dynamic from "next/dynamic"
import type React from "react"
import Link from "next/link"
import {
  FileText,
  FolderOpen,
  Headset,
  LayoutDashboard,
  ShieldCheck,
  Tags,
  TrendingUp,
  Users,
} from "lucide-react"
import { useQuery } from "@tanstack/react-query"
import { Card, CardContent, CardHeader, CardTitle } from "@ui/components/card"
import { PageSection } from "@ui/components/layout"
import { Skeleton } from "@ui/components/skeleton"
import { TypographyH1 } from "@ui/components/typography"
import {
  ADMIN_PAGE_SUBTITLE_CLASS,
  ADMIN_PAGE_TITLE_ICON_CLASS,
  ADMIN_PAGE_TITLE_PRIMARY_CLASS,
} from "@ui/lib/layout-shell"
import { PERMISSION_CODES } from "@workspace/api-client"
import { useAuth } from "@/providers/auth-provider"
import { api } from "@/lib/api"
import type { DashboardStatsDto, DashboardOverviewDto } from "@/types/dashboard"

const MonthlyLineChart = dynamic(
  () => import("@/components/dashboard-charts").then((m) => m.MonthlyLineChart),
  { ssr: false }
)
const MonthlyBarChart = dynamic(
  () => import("@/components/dashboard-charts").then((m) => m.MonthlyBarChart),
  { ssr: false }
)
const CategoryDoughnutChart = dynamic(
  () =>
    import("@/components/dashboard-charts").then(
      (m) => m.CategoryDoughnutChart
    ),
  { ssr: false }
)
const TopPostsChart = dynamic(
  () => import("@/components/dashboard-charts").then((m) => m.TopPostsChart),
  { ssr: false }
)

type StatCard = {
  label: string
  value: number | undefined
  isLoading: boolean
  icon: React.ElementType
  href: string
  color: string
  change?: number
}

function StatCardSkeleton() {
  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
        <Skeleton className="h-4 w-24" />
        <Skeleton className="size-8 rounded-lg" />
      </CardHeader>
      <CardContent>
        <Skeleton className="mb-1 h-8 w-16" />
        <Skeleton className="h-3 w-28" />
      </CardContent>
    </Card>
  )
}

function StatCardItem({ card }: { card: StatCard }) {
  const Icon = card.icon
  return (
    <Link href={card.href} className="group block">
      <Card className="transition-all duration-200 group-hover:border-primary/30 hover:-translate-y-px hover:shadow-md">
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium text-muted-foreground">
            {card.label}
          </CardTitle>
          <div
            className={`flex size-8 items-center justify-center rounded-lg ${card.color}`}
          >
            <Icon className="size-4" />
          </div>
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-extrabold tracking-tight text-foreground">
            {card.value ?? "—"}
          </div>
          <p className="mt-0.5 text-xs text-muted-foreground">Xem chi tiết →</p>
        </CardContent>
      </Card>
    </Link>
  )
}

type QuickLink = {
  href: string
  label: string
  description: string
  icon: React.ElementType
  permission: (typeof PERMISSION_CODES)[keyof typeof PERMISSION_CODES] | null
}

export const QUICK_LINKS: QuickLink[] = [
  {
    href: "/posts",
    label: "Quản lý bài viết",
    description: "Tạo, chỉnh sửa và xuất bản bài viết",
    icon: FileText,
    permission: null,
  },
  {
    href: "/categories",
    label: "Danh mục nội dung",
    description: "Cây danh mục phân cấp cho bài viết",
    icon: FolderOpen,
    permission: null,
  },
  {
    href: "/tags",
    label: "Thẻ nội dung",
    description: "Gán thẻ phân loại bài viết",
    icon: Tags,
    permission: PERMISSION_CODES.TAGS_VIEW,
  },
  {
    href: "/staff",
    label: "Nhân sự & tài khoản",
    description: "Quản lý tài khoản nhân viên",
    icon: Users,
    permission: PERMISSION_CODES.USERS_MANAGE,
  },
  {
    href: "/rbac",
    label: "Vai trò & phân quyền",
    description: "Cấu hình quyền truy cập hệ thống",
    icon: ShieldCheck,
    permission: PERMISSION_CODES.RBAC_READ,
  },
  {
    href: "/contact-requests",
    label: "Yêu cầu liên hệ",
    description: "Xử lý yêu cầu hỗ trợ từ khách hàng",
    icon: Headset,
    permission: PERMISSION_CODES.CONTACT_REQUESTS_VIEW,
  },
]

function buildStats(
  overview: DashboardOverviewDto | undefined,
  isLoading: boolean
): StatCard[] {
  return [
    {
      label: "Bài viết",
      value: overview?.totalPosts,
      isLoading,
      icon: FileText,
      href: "/posts",
      color: "bg-blue-500/10 text-blue-600 dark:text-blue-400",
      change: overview?.postsChange,
    },
    {
      label: "Danh mục",
      value: overview?.totalCategories,
      isLoading,
      icon: FolderOpen,
      href: "/categories",
      color: "bg-amber-500/10 text-amber-600 dark:text-amber-400",
      change: overview?.categoriesChange,
    },
    {
      label: "Tài khoản",
      value: overview?.totalUsers,
      isLoading,
      icon: Users,
      href: "/staff",
      color: "bg-violet-500/10 text-violet-600 dark:text-violet-400",
      change: overview?.usersChange,
    },
    {
      label: "Liên hệ",
      value: overview?.totalContactRequests,
      isLoading,
      icon: Headset,
      href: "/contact-requests",
      color: "bg-rose-500/10 text-rose-600 dark:text-rose-400",
      change: overview?.contactRequestsChange,
    },
  ]
}

export default function AdminDashboardPage() {
  const { user } = useAuth()

  const displayName = user?.name?.trim() || user?.email || "Người dùng"

  const { data, isLoading } = useQuery<DashboardStatsDto>({
    queryKey: ["dashboard", "stats"],
    queryFn: async () => {
      const payload = await api.http.get<unknown>("/admin/dashboard/stats")
      const envelope = payload as {
        success?: boolean
        data?: DashboardStatsDto
      }
      return envelope.data as DashboardStatsDto
    },
    staleTime: 60_000,
  })

  const stats = buildStats(data?.overview, isLoading)

  return (
    <PageSection max="full" className="min-w-0 space-y-8">
      {/* Header */}
      <div>
        <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
          <LayoutDashboard
            className={ADMIN_PAGE_TITLE_ICON_CLASS}
            aria-hidden
          />
          Tổng quan hệ thống
        </TypographyH1>
        <p className={ADMIN_PAGE_SUBTITLE_CLASS}>
          Xin chào,{" "}
          <span className="font-semibold text-foreground">{displayName}</span>.
          Đây là bảng điều khiển quản trị HUB Parent.
        </p>
      </div>

      {/* Stat cards */}
      <div>
        <div className="mb-3 flex items-center gap-2 text-sm font-semibold tracking-wide text-muted-foreground uppercase">
          <TrendingUp className="size-4" aria-hidden />
          Tổng quan dữ liệu
        </div>
        <div className="grid grid-cols-2 gap-4 lg:grid-cols-4">
          {stats.map((card) =>
            card.isLoading ? (
              <StatCardSkeleton key={card.label} />
            ) : (
              <StatCardItem key={card.label} card={card} />
            )
          )}
        </div>
      </div>

      {/* Charts */}
      {data && (data.monthlyData?.length ?? 0) > 0 && (
        <div className="space-y-4">
          <div className="mb-1 flex items-center gap-2 text-sm font-semibold tracking-wide text-muted-foreground uppercase">
            <TrendingUp className="size-4" aria-hidden />
            Biểu đồ thống kê
          </div>
          <div className="grid gap-4 lg:grid-cols-2">
            <MonthlyLineChart data={data.monthlyData} />
            <MonthlyBarChart data={data.monthlyData} />
          </div>
          <div className="grid gap-4 lg:grid-cols-2">
            {(data.categoryData?.length ?? 0) > 0 && (
              <CategoryDoughnutChart data={data.categoryData} />
            )}
            {(data.topPosts?.length ?? 0) > 0 && (
              <TopPostsChart data={data.topPosts} />
            )}
          </div>
        </div>
      )}
    </PageSection>
  )
}

src/app/parent-students/page.tsx.content:
"use client";

import { useMemo, useState } from "react";
import {
  UserCheck,
  Clock,
  CheckCircle2,
  XCircle,
  RefreshCw,
  User,
  GraduationCap,
} from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import type { ColumnDef } from "@tanstack/react-table";
import { Button } from "@ui/components/button";
import { Badge } from "@ui/components/badge";
import { PageSection } from "@ui/components/layout";
import { TypographyH1 } from "@ui/components/typography";
import {
  ADMIN_ALERT_DIALOG_CONTENT_CLASS,
  ADMIN_PAGE_TITLE_PRIMARY_CLASS,
  ADMIN_PAGE_TITLE_ICON_CLASS,
  ADMIN_PAGE_SUBTITLE_CLASS,
} from "@ui/lib/layout-shell";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";
import { AdminDataTable } from "@/components/admin-data-table";
import { AdminConfirmActionDialog } from "@/components/admin-confirm-action-dialog";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";

interface ParentStudentRow {
  id: string;
  parentId: string;
  studentCode: string;
  studentName: string | null;
  note: string | null;
  status: "pending" | "approved" | "rejected";
  reviewedBy: string | null;
  reviewedAt: string | null;
  createdAt: string;
  updatedAt: string;
}

interface ListResult {
  data: ParentStudentRow[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}

type ConfirmAction =
  | { kind: "approve"; row: ParentStudentRow }
  | { kind: "reject"; row: ParentStudentRow };

const STATUS_CONFIG = {
  pending: {
    label: "Chờ duyệt",
    icon: Clock,
    className:
      "bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-950/30 dark:text-amber-400",
  },
  approved: {
    label: "Đã duyệt",
    icon: CheckCircle2,
    className:
      "bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400",
  },
  rejected: {
    label: "Từ chối",
    icon: XCircle,
    className:
      "bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-950/30 dark:text-rose-400",
  },
};

function AdminParentStudentsPageInner() {
  const queryClient = useQueryClient();
  const [statusFilter, setStatusFilter] = useState("pending");
  const [confirmAction, setConfirmAction] = useState<ConfirmAction | null>(null);

  const { data, isLoading, refetch } = useQuery<ListResult>({
    queryKey: ["admin", "parent-students", statusFilter],
    queryFn: async () => {
      const qs = new URLSearchParams({ status: statusFilter, limit: "50" });
      const payload = await api.http.get<unknown>(
        `/admin/parent-students?${qs.toString()}`,
      );
      const envelope = payload as { data?: ListResult };
      return (
        envelope.data ?? {
          data: [],
          pagination: { page: 1, limit: 50, total: 0, totalPages: 0 },
        }
      );
    },
    staleTime: 20_000,
  });

  const reviewMutation = useMutation({
    mutationFn: async ({
      id,
      action,
    }: {
      id: string;
      action: "approved" | "rejected";
    }) => {
      await api.http.patch(`/admin/parent-students/${id}/review`, { action });
    },
    onSuccess: (_, vars) => {
      toast.success(
        vars.action === "approved" ? "Đã duyệt yêu cầu" : "Đã từ chối yêu cầu",
      );
      void queryClient.invalidateQueries({ queryKey: ["admin", "parent-students"] });
      setConfirmAction(null);
    },
    onError: () => toast.error("Lỗi xử lý yêu cầu"),
  });

  const pendingCount =
    statusFilter === "pending" ? (data?.pagination.total ?? 0) : null;

  const columns = useMemo<ColumnDef<ParentStudentRow, unknown>[]>(
    () => [
      {
        id: "parent",
        header: "Phụ huynh",
        enableColumnFilter: false,
        cell: ({ row }) => (
          <div className="flex items-center gap-2">
            <div className="flex size-7 shrink-0 items-center justify-center rounded-full bg-blue-500/10 text-blue-600 dark:text-blue-400">
              <User className="size-3.5" />
            </div>
            <span className="font-mono text-xs text-muted-foreground">
              {row.original.parentId.slice(0, 8)}…
            </span>
          </div>
        ),
      },
      {
        id: "student",
        header: "Học sinh",
        enableColumnFilter: false,
        cell: ({ row }) => (
          <div className="flex items-center gap-2">
            <GraduationCap className="size-4 shrink-0 text-muted-foreground" />
            <div>
              {row.original.studentName && (
                <p className="font-medium">{row.original.studentName}</p>
              )}
              <p className="font-mono text-xs text-muted-foreground">
                {row.original.studentCode}
              </p>
            </div>
          </div>
        ),
      },
      {
        accessorKey: "note",
        header: "Ghi chú",
        cell: ({ getValue }) => {
          const v = getValue() as string | null;
          return v ? (
            <span className="text-xs text-muted-foreground">{v}</span>
          ) : (
            <span className="text-xs italic opacity-40">Không có</span>
          );
        },
      },
      {
        accessorKey: "createdAt",
        header: "Ngày gửi",
        enableColumnFilter: false,
        cell: ({ getValue }) =>
          new Date(getValue() as string).toLocaleDateString("vi-VN", {
            day: "2-digit",
            month: "2-digit",
            year: "numeric",
          }),
      },
      {
        accessorKey: "status",
        header: "Trạng thái",
        enableColumnFilter: false,
        cell: ({ getValue }) => {
          const s = getValue() as ParentStudentRow["status"];
          const cfg = STATUS_CONFIG[s];
          const StatusIcon = cfg.icon;
          return (
            <Badge className={cfg.className} variant="secondary">
              <StatusIcon className="mr-1 size-3" />
              {cfg.label}
            </Badge>
          );
        },
      },
      ...(statusFilter === "pending"
        ? [
            {
              id: "actions",
              header: "Thao tác",
              enableColumnFilter: false,
              cell: ({ row }: { row: { original: ParentStudentRow } }) => (
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    className="h-7 gap-1 border-emerald-200 px-2 text-xs text-emerald-700 hover:bg-emerald-50 dark:border-emerald-800 dark:text-emerald-400"
                    onClick={() =>
                      setConfirmAction({ kind: "approve", row: row.original })
                    }
                  >
                    <CheckCircle2 className="size-3.5" />
                    Duyệt
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    className="h-7 gap-1 border-rose-200 px-2 text-xs text-rose-700 hover:bg-rose-50 dark:border-rose-800 dark:text-rose-400"
                    onClick={() =>
                      setConfirmAction({ kind: "reject", row: row.original })
                    }
                  >
                    <XCircle className="size-3.5" />
                    Từ chối
                  </Button>
                </div>
              ),
            } as ColumnDef<ParentStudentRow, unknown>,
          ]
        : []),
    ],
    [statusFilter],
  );

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <div className="flex items-start justify-between gap-4">
        <div>
          <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
            <UserCheck className={ADMIN_PAGE_TITLE_ICON_CLASS} aria-hidden />
            Duyệt liên kết học sinh
          </TypographyH1>
          <p className={ADMIN_PAGE_SUBTITLE_CLASS}>
            Xem xét và duyệt yêu cầu liên kết học sinh từ phụ huynh.
            {pendingCount != null && pendingCount > 0 && (
              <span className="ml-2 inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-semibold text-amber-700 dark:bg-amber-950/40 dark:text-amber-400">
                {pendingCount} chờ duyệt
              </span>
            )}
          </p>
        </div>
        <Button
          variant="outline"
          size="sm"
          className="shrink-0 gap-1.5"
          onClick={() => refetch()}
        >
          <RefreshCw className="size-3.5" />
          Làm mới
        </Button>
      </div>

      <AdminDataTable<ParentStudentRow>
        data={data?.data ?? []}
        columns={columns}
        getRowId={(row) => row.id}
        isLoading={isLoading}
        emptyLabel="Không có yêu cầu nào."
        getGlobalFilterText={(row) =>
          `${row.studentCode} ${row.studentName ?? ""} ${row.parentId}`
        }
        globalFilterPlaceholder="Tìm mã sinh viên, họ tên, ID phụ huynh…"
        filterToolbarExtra={
          <Select value={statusFilter} onValueChange={(v) => { if (v) setStatusFilter(v); }}>
            <SelectTrigger className="h-9 w-40 shrink-0 rounded-lg">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="pending">Chờ duyệt</SelectItem>
              <SelectItem value="approved">Đã duyệt</SelectItem>
              <SelectItem value="rejected">Từ chối</SelectItem>
            </SelectContent>
          </Select>
        }
      />

      <AdminConfirmActionDialog
        open={confirmAction != null}
        onOpenChange={(open) => {
          if (!open) setConfirmAction(null);
        }}
        contentClassName={ADMIN_ALERT_DIALOG_CONTENT_CLASS}
        footerClassName="gap-2"
        icon={
          confirmAction?.kind === "approve" ? (
            <CheckCircle2 className="size-5 shrink-0 text-emerald-600" aria-hidden />
          ) : (
            <XCircle className="size-5 shrink-0 text-destructive" aria-hidden />
          )
        }
        title={
          confirmAction?.kind === "approve"
            ? "Duyệt yêu cầu liên kết?"
            : "Từ chối yêu cầu liên kết?"
        }
        description={
          confirmAction?.kind === "approve"
            ? `Duyệt liên kết học sinh «${confirmAction.row.studentCode}». Phụ huynh sẽ được xem bảng điểm sau khi duyệt.`
            : confirmAction?.kind === "reject"
              ? `Từ chối liên kết học sinh «${confirmAction.row.studentCode}». Phụ huynh sẽ thấy thông báo bị từ chối.`
              : null
        }
        confirmLabel={confirmAction?.kind === "approve" ? "Duyệt" : "Từ chối"}
        confirmDestructive={confirmAction?.kind === "reject"}
        confirmDisabled={reviewMutation.isPending}
        confirmLoading={reviewMutation.isPending}
        onConfirm={() => {
          if (!confirmAction) return;
          reviewMutation.mutate({
            id: confirmAction.row.id,
            action: confirmAction.kind === "approve" ? "approved" : "rejected",
          });
        }}
      />
    </PageSection>
  );
}

export default function AdminParentStudentsPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin"]}>
      <AdminParentStudentsPageInner />
    </AdminPageGuard>
  );
}

src/app/posts/new/page.tsx.content:
"use client";

import { useCallback, useMemo } from "react";
import { useRouter } from "next/navigation";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { PageSection } from "@ui/components/layout";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";
import {
  PostFormShell,
  usePostForm,
  buildCategoryOptionTree,
} from "../_component";
import { useCategoriesQuery, useTagsQuery } from "../_component/_query";
import type { PostFormValues } from "../_component";

function NewPostPageInner() {
  const router = useRouter();
  const queryClient = useQueryClient();
  const form = usePostForm();

  const categoriesQuery = useCategoriesQuery(api);
  const tagsQuery = useTagsQuery(api);

  const categoryTreeOptions = useMemo(
    () => buildCategoryOptionTree(categoriesQuery.data ?? []),
    [categoriesQuery.data],
  );

  const createMutation = useMutation({
    mutationFn: async (input: Record<string, unknown>) =>
      api.http.post("/admin/posts", input),
    onSuccess: async (_data, variables) => {
      await queryClient.invalidateQueries({ queryKey: ["media", "posts"] });
      toast.success(`Đã tạo bài viết "${(variables.title as string)?.trim()}"`);
      router.push("/posts");
    },
    onError: (err: unknown) => {
      const message = err instanceof Error ? err.message : "Không thể tạo bài viết";
      toast.error(message);
    },
  });

  const handleSubmit = useCallback(
    async (values: PostFormValues) => {
      const payload = {
        title: values.title.trim(),
        slug: values.slug.trim() || values.title.trim().toLowerCase().replace(/\s+/g, "-"),
        excerpt: values.excerpt.trim() || null,
        image: values.image.trim() || null,
        content: values.content,
        published: values.published,
        publishedAt: values.publishedAt || null,
        categoryIds: values.categoryIds,
        tagIds: values.tagIds,
      };
      await createMutation.mutateAsync(payload);
    },
    [createMutation],
  );

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <PostFormShell
        form={form}
        onSubmit={handleSubmit}
        submitting={createMutation.isPending}
        editingId={null}
        categoryTreeOptions={categoryTreeOptions}
        tagsOptions={tagsQuery.data ?? []}
        onBack={() => router.push("/posts")}
        onReset={() => { form.reset(); }}
      />
    </PageSection>
  );
}

export default function NewPostPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin", "manager"]}>
      <NewPostPageInner />
    </AdminPageGuard>
  );
}

