src/app/posts/_component/types.ts.content:
export type TaxonomyOption = {
  id: string;
  name: string;
};

export type CategoryTreeOption = TaxonomyOption & {
  parentId?: string | null;
  sortOrder?: number;
  subRows?: CategoryTreeOption[];
};

export type PostListRow = {
  id: string;
  title: string;
  slug: string;
  excerpt: string | null;
  image: string | null;
  published: boolean;
  publishedAt: string | null;
  createdAt: string;
  updatedAt: string;
  deletedAt: string | null;
  author: {
    id: string;
    name: string | null;
    email: string;
  };
  categories: TaxonomyOption[];
  tags: TaxonomyOption[];
};

export type PostConfirmAction =
  | { kind: "delete"; row: PostListRow }
  | { kind: "restore"; row: PostListRow }
  | { kind: "purge"; row: PostListRow };

export type PostDetail = PostListRow & {
  content: unknown;
};

export type PagedResult<T> = { items: T[]; total: number };
export type ApiEnvelope<T> = {
  success?: boolean;
  message?: string;
  error?: string | null;
  data?: T;
};
export type PagedApiShape<T> = {
  data: T[];
  pagination?: { total?: number };
};

export type FormState = {
  id?: string;
  title: string;
  slug: string;
  excerpt: string;
  image: string;
  content: unknown;
  published: boolean;
  publishedAt: string;
  categoryIds: string[];
  tagIds: string[];
};

export type EditorTextNodeShape = {
  detail: number;
  format: number;
  mode: "normal";
  style: string;
  text: string;
  type: "text";
  version: 1;
};

export type EditorParagraphNodeShape = {
  children: EditorTextNodeShape[];
  direction: null;
  format: string;
  indent: number;
  textFormat: number;
  textStyle: string;
  type: "paragraph";
  version: 1;
};

export type EditorStateShape = {
  root: {
    children: EditorParagraphNodeShape[];
    direction: null;
    format: string;
    indent: number;
    type: "root";
    version: 1;
  };
};

src/app/posts/_component/utils.ts.content:
import type { SerializedEditorState } from "lexical";
import type { SerializedLexicalNode } from "lexical";
import type {
  ApiEnvelope,
  CategoryTreeOption,
  EditorParagraphNodeShape,
  EditorStateShape,
  PagedApiShape,
  PagedResult,
} from "./types";

export function createParagraphNode(text = ""): EditorParagraphNodeShape {
  return {
    children: text
      ? [
          {
            detail: 0,
            format: 0,
            mode: "normal",
            style: "",
            text,
            type: "text",
            version: 1,
          },
        ]
      : [],
    direction: null,
    format: "",
    indent: 0,
    textFormat: 0,
    textStyle: "",
    type: "paragraph",
    version: 1,
  };
}

export function createSerializedEditorState(
  paragraphs: EditorParagraphNodeShape[]
): SerializedEditorState {
  const state: EditorStateShape = {
    root: {
      children: paragraphs,
      direction: null,
      format: "",
      indent: 0,
      type: "root",
      version: 1,
    },
  };
  return state as SerializedEditorState;
}

export function slugify(input: string): string {
  return input
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export function getSeoStatus(
  length: number,
  recommendedMin: number,
  recommendedMax: number
) {
  if (length === 0) {
    return {
      label: "Chưa có nội dung",
      tone: "destructive" as const,
      hint: `Nên nhập khoảng ${recommendedMin}-${recommendedMax} ký tự.`,
    };
  }
  if (length < recommendedMin) {
    return {
      label: "Hơi ngắn",
      tone: "secondary" as const,
      hint: `Nên tăng lên khoảng ${recommendedMin}-${recommendedMax} ký tự.`,
    };
  }
  if (length > recommendedMax) {
    return {
      label: "Hơi dài",
      tone: "secondary" as const,
      hint: `Nên rút xuống khoảng ${recommendedMin}-${recommendedMax} ký tự.`,
    };
  }
  return {
    label: "Tốt cho SEO",
    tone: "default" as const,
    hint: `Độ dài đang nằm trong khoảng gợi ý ${recommendedMin}-${recommendedMax} ký tự.`,
  };
}

export function buildCategoryOptionTree(
  rows: CategoryTreeOption[]
): CategoryTreeOption[] {
  const byId = new Map<string, CategoryTreeOption>();

  for (const row of rows) {
    byId.set(row.id, {
      ...row,
      subRows: [],
    });
  }

  const roots: CategoryTreeOption[] = [];
  for (const row of byId.values()) {
    const parentId = row.parentId ?? null;
    if (parentId && byId.has(parentId)) {
      byId.get(parentId)?.subRows?.push(row);
      continue;
    }
    roots.push(row);
  }

  const sortTree = (items: CategoryTreeOption[]): CategoryTreeOption[] =>
    [...items]
      .sort((a, b) => {
        const sortDelta = (a.sortOrder ?? 0) - (b.sortOrder ?? 0);
        if (sortDelta !== 0) return sortDelta;
        return a.name.localeCompare(b.name, "vi");
      })
      .map((item) => ({
        ...item,
        subRows: sortTree(item.subRows ?? []),
      }));

  return sortTree(roots);
}

export function unwrapEnvelope<T>(payload: unknown): T {
  if (!payload || typeof payload !== "object") return payload as T;
  const envelope = payload as ApiEnvelope<T>;
  if (envelope.success === false) {
    throw new Error(envelope.message || envelope.error || "Yeu cau that bai");
  }
  return "data" in envelope ? (envelope.data as T) : (payload as T);
}

export function normalizePaged<T>(payload: unknown): PagedResult<T> {
  const data = unwrapEnvelope<PagedApiShape<T> | T[]>(payload);
  if (Array.isArray(data)) {
    return { items: data, total: data.length };
  }
  return {
    items: data.data ?? [],
    total: data.pagination?.total ?? data.data?.length ?? 0,
  };
}

export function buildPostsFilterQuery(
  filters: { id: string; value: unknown }[]
): Record<string, string> {
  const query: Record<string, string> = {};
  for (const filter of filters) {
    const { value } = filter;
    if (value === undefined || value === null || value === "") continue;

    if (filter.id === "published") {
      if (Array.isArray(value)) {
        const vals = value.map((v) => String(v)).filter(Boolean);
        if (vals.length) query.published = vals.join(",");
      } else {
        const v = String(value).trim();
        if (v) query.published = v;
      }
    } else if (filter.id === "categoryId") {
      if (Array.isArray(value)) {
        const vals = value.map((v) => String(v)).filter(Boolean);
        if (vals.length) query.categoryId = vals.join(",");
      } else if (typeof value === "string" && value.includes(",")) {
        const vals = value.split(",").map((v) => v.trim()).filter(Boolean);
        if (vals.length) query.categoryId = vals.join(",");
      } else {
        const v = String(value).trim();
        if (v) query.categoryId = v;
      }
    } else if (filter.id === "tagId") {
      if (Array.isArray(value)) {
        const vals = value.map((v) => String(v)).filter(Boolean);
        if (vals.length) query.tagId = vals.join(",");
      } else {
        const v = String(value).trim();
        if (v) query.tagId = v;
      }
    } else if (filter.id === "updatedAt") {
      const v = String(value).trim();
      if (v) query.updatedAt = v;
    }
  }
  return query;
}

export function isSerializedEditorState(
  value: unknown
): value is SerializedEditorState<SerializedLexicalNode> {
  return (
    typeof value === "object" &&
    value !== null &&
    "root" in value &&
    typeof (value as Record<string, unknown>).root === "object"
  );
}

export function fromLocalInputValue(value: string): string {
  if (!value) return "";
  try {
    const date = new Date(value);
    if (!isNaN(date.getTime())) {
      return date.toISOString();
    }
  } catch {
    // Ignore
  }
  return value;
}

export function toLocalInputValue(value: string): string {
  if (!value) return "";
  try {
    const date = new Date(value);
    if (!isNaN(date.getTime())) {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, "0");
      const day = String(date.getDate()).padStart(2, "0");
      const hours = String(date.getHours()).padStart(2, "0");
      const minutes = String(date.getMinutes()).padStart(2, "0");
      return `${year}-${month}-${day}T${hours}:${minutes}`;
    }
  } catch {
    // Ignore
  }
  return value;
}

export function formatDateTime(value: string): string {
  if (!value) return "";
  try {
    const date = new Date(value);
    if (!isNaN(date.getTime())) {
      const day = String(date.getDate()).padStart(2, "0");
      const month = String(date.getMonth() + 1).padStart(2, "0");
      const year = date.getFullYear();
      const hours = String(date.getHours()).padStart(2, "0");
      const minutes = String(date.getMinutes()).padStart(2, "0");
      return `${day}/${month}/${year} ${hours}:${minutes}`;
    }
  } catch {
    // Ignore
  }
  return "";
}

const EMPTY_EDITOR_PARAGRAPHS: EditorParagraphNodeShape[] = [createParagraphNode()];
const EMPTY_EDITOR_STATE = createSerializedEditorState(EMPTY_EDITOR_PARAGRAPHS);

function createEditorStateFromPlainText(raw: string): SerializedEditorState {
  const lines = raw
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line, index, arr) => line !== "" || index < arr.length - 1);
  const paragraphs =
    lines.length > 0 ? lines.map((line) => createParagraphNode(line)) : EMPTY_EDITOR_PARAGRAPHS;

  return createSerializedEditorState(paragraphs);
}

export function normalizeContentForEditor(value: unknown): SerializedEditorState {
  if (isSerializedEditorState(value)) return value;
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed.startsWith("{")) {
      try {
        const parsed = JSON.parse(trimmed) as unknown;
        if (isSerializedEditorState(parsed)) {
          return parsed;
        }
      } catch {
        // Fallback to plain text import below.
      }
    }

    const plainText =
      typeof window !== "undefined" && /<[^>]+>/.test(value)
        ? new DOMParser().parseFromString(value, "text/html").body.textContent ?? value
        : value;
    return createEditorStateFromPlainText(plainText);
  }
  return EMPTY_EDITOR_STATE;
}

