import type { UseMutationResult } from "@tanstack/react-query";
import { useMutation } from "@tanstack/react-query";
import type { StoreSyncSdk } from "@workspace/api-client";
import type { PostListRow } from "../types";
import { unwrapEnvelope } from "../utils";

export interface UsePostsMutationsProps {
  api: StoreSyncSdk;
  invalidateAll: () => Promise<void>;
}

export function useDeleteMutation({
  api,
  invalidateAll,
}: UsePostsMutationsProps): UseMutationResult<unknown, Error, string, unknown> {
  return useMutation({
    mutationFn: async (id: string) => api.http.delete(`/admin/posts/${id}`),
    onSuccess: invalidateAll,
  });
}

export function useRestoreMutation({
  api,
  invalidateAll,
}: UsePostsMutationsProps): UseMutationResult<PostListRow, Error, string, unknown> {
  return useMutation({
    mutationFn: async (id: string) =>
      unwrapEnvelope<PostListRow>(await api.http.post(`/admin/posts/${id}/restore`)),
    onSuccess: invalidateAll,
  });
}

export function usePurgeMutation({
  api,
  invalidateAll,
}: UsePostsMutationsProps): UseMutationResult<unknown, Error, string, unknown> {
  return useMutation({
    mutationFn: async (id: string) => api.http.delete(`/admin/posts/${id}/hard-delete`),
    onSuccess: invalidateAll,
  });
}

export function useBulkMutation({
  api,
  invalidateAll,
}: UsePostsMutationsProps): UseMutationResult<unknown, Error, { action: "delete" | "restore" | "hard-delete"; ids: string[] }, unknown> {
  return useMutation({
    mutationFn: async (input: {
      action: "delete" | "restore" | "hard-delete";
      ids: string[];
    }) => api.http.post("/admin/posts/bulk", input),
    onSuccess: invalidateAll,
  });
}

import type { UseQueryResult } from "@tanstack/react-query";
import { useQuery } from "@tanstack/react-query";
import type { StoreSyncSdk } from "@workspace/api-client";
import type { PostListRow, PagedResult } from "../types";
import { normalizePaged } from "../utils";

export interface UsePostsQueriesProps {
  api: StoreSyncSdk;
  page: number;
  pageSize: number;
  debouncedQ: string;
  postColumnFilterQuery: Record<string, unknown>;
}

export function usePostsQuery({
  api,
  page,
  pageSize,
  debouncedQ,
  postColumnFilterQuery,
}: UsePostsQueriesProps): UseQueryResult<PagedResult<PostListRow>> {
  return useQuery({
    queryKey: ["media", "posts", "list", page, pageSize, debouncedQ, postColumnFilterQuery],
    queryFn: async (): Promise<PagedResult<PostListRow>> =>
      normalizePaged(
        await api.http.get("/admin/posts", {
          query: {
            page,
            limit: pageSize,
            search: debouncedQ.trim() || undefined,
            status: "active",
            ...Object.fromEntries(
              Object.entries(postColumnFilterQuery).map(([key, value]) => [
                `filter[${key}]`,
                value,
              ]),
            ),
          },
        }),
      ),
  });
}

export interface UseTrashQueryProps {
  api: StoreSyncSdk;
  trashPage: number;
  trashPageSize: number;
  debouncedTrashQ: string;
  trashColumnFilterQuery?: Record<string, unknown>;
  enabled: boolean;
}

export function useTrashQuery({
  api,
  trashPage,
  trashPageSize,
  debouncedTrashQ,
  trashColumnFilterQuery,
  enabled,
}: UseTrashQueryProps): UseQueryResult<PagedResult<PostListRow>> {
  return useQuery({
    queryKey: ["media", "posts", "trash", trashPage, trashPageSize, debouncedTrashQ, trashColumnFilterQuery],
    enabled,
    queryFn: async (): Promise<PagedResult<PostListRow>> =>
      normalizePaged(
        await api.http.get("/admin/posts", {
          query: {
            page: trashPage,
            limit: trashPageSize,
            search: debouncedTrashQ.trim() || undefined,
            status: "deleted",
            ...Object.fromEntries(
              Object.entries(trashColumnFilterQuery ?? {}).map(([key, value]) => [
                `filter[${key}]`,
                value,
              ]),
            ),
          },
        }),
      ),
  });
}

