src/components/admin-page-guard.tsx.content:
"use client";

import type { ReactNode } from "react";
import { AlertCircle } from "lucide-react";
import { Card, CardDescription, CardHeader, CardTitle } from "@ui/components/card";
import { canUserAccess, type PermissionCode } from "@workspace/api-client";
import { useAuth } from "@/providers/auth-provider";

const BYPASS_ROLES = ["super_admin", "admin"] as const;

interface AdminPageGuardProps {
  /** Quyền bắt buộc — nếu không có sẽ hiện màn hình "Không có quyền". */
  permission?: PermissionCode;
  /** Danh sách role được phép (khớp role.name). */
  roles?: string[];
  children: ReactNode;
}

/**
 * Bọc nội dung trang, hiện thông báo lỗi khi user không đủ quyền.
 * Super admin (super_admin role) luôn được phép.
 */
export function AdminPageGuard({ permission, roles, children }: AdminPageGuardProps) {
  const { user } = useAuth();

  if (!user) return null;

  const isBypassRole = user.roles?.some((r) => (BYPASS_ROLES as readonly string[]).includes(r.name)) ?? false;
  if (isBypassRole) return <>{children}</>;

  if (roles?.length) {
    const hasRole = user.roles?.some((r) => roles.includes(r.name)) ?? false;
    if (!hasRole) return <AccessDenied />;
  }

  if (permission) {
    if (!canUserAccess(user, permission)) return <AccessDenied />;
  }

  return <>{children}</>;
}

function AccessDenied() {
  return (
    <div className="p-6">
      <Card className="border-destructive/30 bg-destructive/5">
        <CardHeader className="flex flex-row items-start gap-3 space-y-0">
          <AlertCircle className="mt-0.5 size-5 shrink-0 text-destructive" />
          <div>
            <CardTitle className="text-base">Không có quyền truy cập</CardTitle>
            <CardDescription className="mt-1">
              Tài khoản của bạn không có quyền xem trang này.
            </CardDescription>
          </div>
        </CardHeader>
      </Card>
    </div>
  );
}

src/components/admin-shell.tsx.content:
"use client";

import { useEffect, useState, type ReactNode } from "react";
import { usePathname, useRouter } from "next/navigation";
import {
  ChevronDown,
  Menu,
  Monitor,
  Moon,
  PanelLeftClose,
  PanelLeft,
  Sun,
  UserCircle2,
} from "lucide-react";
import { Button } from "@ui/components/button";
import { cn } from "@ui/lib/utils";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@ui/components/dropdown-menu";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "@ui/components/sheet";
import { MobileSidebarPanel, Sidebar } from "@/components/sidebar";
import { ThemeToggle } from "@ui/components/theme-toggle";
import { Page, PageContent } from "@ui/components/layout";
import { TypographyH2 } from "@ui/components/typography";
import { useTextSize } from "@ui/components/text-size-provider";
import { useTheme } from "@ui/components/theme-provider";
import { canAccessStaffAdmin } from "@workspace/api-client";
import { useAuth, useClientReady } from "@/providers/auth-provider";
import { AdminNotificationBell } from "@/components/admin-notification-bell";
import { ScrollToTop } from "@/components/scroll-to-top";
import {
  ADMIN_SESSION_EVENT,
  clearAdminSession,
} from "@/lib/auth-session";
import {
  AUTH_LOGIN_PATH,
  isAuthPath,
} from "@/lib/auth-routes";
import {
  ADMIN_HEADER_ROLE_LINE_CLASS,
  ADMIN_MAIN_SCROLL_CLASS,
  ADMIN_PAGE_CONTENT_CLASS,
  ADMIN_SHEET_NAV_CLASS,
} from "@ui/lib/layout-shell";

const SIDEBAR_COLLAPSED_KEY = "admin-sidebar-collapsed";

const HEADER_ICON_BTN_MOBILE = cn(
  "h-11 w-11 min-h-11 min-w-11 shrink-0 rounded-lg border-border/70 bg-background/90 text-muted-foreground shadow-sm",
  "hover:border-primary/40 hover:bg-primary/5 hover:text-primary hover:shadow active:scale-[0.98] md:hidden [&_svg]:size-5",
);

const HEADER_ICON_BTN_DESKTOP = cn(
  "hidden h-10 w-10 shrink-0 rounded-lg border-border/70 bg-background/90 text-muted-foreground shadow-sm",
  "hover:border-primary/40 hover:bg-primary/5 hover:text-primary hover:shadow active:scale-[0.98] md:inline-flex [&_svg]:size-5",
);

const HEADER_PROFILE_TRIGGER = cn(
  "group relative inline-flex min-h-12 min-w-12 items-center gap-3 rounded-lg border border-border/70 bg-background/95 px-2.5 py-1.5 pr-3 text-left shadow-sm ring-1 ring-black/5 backdrop-blur-xl",
  "transition-all duration-200 hover:-translate-y-px hover:border-primary/25 hover:bg-primary/[0.04] hover:shadow-md",
  "aria-expanded:border-primary/25 aria-expanded:bg-primary/[0.05] aria-expanded:shadow-md",
  "focus-visible:outline-none focus-visible:ring-4 focus-visible:ring-ring/20 supports-[backdrop-filter]:bg-background/75",
);

const HEADER_PROFILE_AVATAR = cn(
  "flex h-10 w-10 shrink-0 items-center justify-center rounded-lg border border-primary/15 bg-gradient-to-br from-primary/15 to-primary/5",
  "text-sm font-extrabold tracking-wide text-primary shadow-inner transition-all duration-200",
  "group-hover:border-primary/25 group-hover:from-primary/20 group-hover:to-primary/10 group-hover:shadow-sm",
  "group-aria-expanded:border-primary/25 group-aria-expanded:from-primary/20 group-aria-expanded:to-primary/10",
);

function initials(name: string): string {
  const p = name.trim().split(/\s+/).filter(Boolean);
  if (p.length === 0) return "?";
  if (p.length === 1) return p[0].slice(0, 2).toUpperCase();
  return (p[0][0] + p[p.length - 1][0]).toUpperCase();
}

function roleSummary(user: { roles: { name: string; displayName: string }[] }): string {
  if (!user.roles.length) return "Chưa gán vai trò";
  return user.roles.map((r) => r.displayName || r.name).join(" · ");
}

function AuthLoadingScreen({ message }: { message: string }) {
  return (
    <div className="min-h-screen flex items-center justify-center bg-muted/30 text-muted-foreground text-sm">
      {message}
    </div>
  );
}

export function AdminShell({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const clientReady = useClientReady();
  const { user } = useAuth();
  const { theme, setTheme } = useTheme();
  const { size, setSize } = useTextSize();
  const displayName = user?.name?.trim() || user?.email || "Người dùng HUB";
  const onAuthRoute = isAuthPath(pathname);
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [mobileNavOpen, setMobileNavOpen] = useState(false);

  useEffect(() => {
    try {
      setSidebarCollapsed(localStorage.getItem(SIDEBAR_COLLAPSED_KEY) === "1");
    } catch {
      /* ignore */
    }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem(SIDEBAR_COLLAPSED_KEY, sidebarCollapsed ? "1" : "0");
    } catch {
      /* ignore */
    }
  }, [sidebarCollapsed]);

  // Force editor toolbar sticky via JS to overcome any CSS specificity issues
  useEffect(() => {
    const forceToolbarSticky = () => {
      document.querySelectorAll<HTMLElement>(".editor-toolbar").forEach((el) => {
        el.style.setProperty("position", "sticky", "important");
        el.style.setProperty("top", "-25px", "important");
      });
    };
    forceToolbarSticky();
    const timer = setTimeout(forceToolbarSticky, 500);
    const observer = new MutationObserver(forceToolbarSticky);
    observer.observe(document.body, { childList: true, subtree: true });
    return () => {
      clearTimeout(timer);
      observer.disconnect();
    };
  }, []);

  useEffect(() => {
    if (!clientReady) return;

    if (onAuthRoute) {
      if (user && canAccessStaffAdmin(user)) {
        router.replace("/");
        return;
      }
      if (user && !canAccessStaffAdmin(user)) {
        clearAdminSession();
        window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
        router.replace(`${AUTH_LOGIN_PATH}?reason=staff_only`);
      }
      return;
    }

    if (!user) {
      router.replace(AUTH_LOGIN_PATH);
      return;
    }
    if (!canAccessStaffAdmin(user)) {
      clearAdminSession();
      window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
      router.replace(`${AUTH_LOGIN_PATH}?reason=staff_only`);
    }
  }, [clientReady, onAuthRoute, user, router]);

  if (onAuthRoute) {
    if (!clientReady) {
      return <AuthLoadingScreen message="Đang tải…" />;
    }
    if (user && canAccessStaffAdmin(user)) {
      return <AuthLoadingScreen message="Đang chuyển về bảng điều khiển…" />;
    }
    return (
      <>
        <div className="fixed right-4 top-4 z-50 rounded-lg border border-border bg-background/90 p-0.5 shadow-sm backdrop-blur-sm">
          <ThemeToggle />
        </div>
        {children}
      </>
    );
  }

  if (!clientReady || !user) {
    return <AuthLoadingScreen message="Đang tải…" />;
  }

  const rolesDisplay = roleSummary(user);

  return (
    <>
    <div className="flex h-screen w-full flex-col bg-background font-sans text-foreground md:flex-row">
        <Sheet open={mobileNavOpen} onOpenChange={setMobileNavOpen}>
          <SheetContent
            id="admin-mobile-nav"
            side="left"
            showCloseButton
            className={ADMIN_SHEET_NAV_CLASS}
          >
            <SheetHeader className="sr-only">
              <SheetTitle>Menu điều hướng</SheetTitle>
            </SheetHeader>
            <MobileSidebarPanel onNavigate={() => setMobileNavOpen(false)} />
          </SheetContent>
        </Sheet>

        <Sidebar collapsed={sidebarCollapsed} />

        <div className="flex min-w-0 flex-1 flex-col overflow-hidden">
          <header data-admin-header="true" className="sticky top-0 z-10 flex min-h-16 shrink-0 items-center justify-between border-b border-border/70 bg-background/85 px-3 shadow-[0_1px_0_0_hsl(var(--border)/0.4)] backdrop-blur-xl supports-[backdrop-filter]:bg-background/75 sm:min-h-[4.5rem] sm:px-5 lg:px-6">
            <div className="flex min-w-0 items-center gap-2 sm:gap-3">
              <Button
                type="button"
                variant="outline"
                size="icon"
                className={HEADER_ICON_BTN_MOBILE}
                onClick={() => setMobileNavOpen(true)}
                aria-label="Mở menu điều hướng"
                aria-expanded={mobileNavOpen}
                aria-controls="admin-mobile-nav"
              >
                <Menu aria-hidden className="size-5" />
              </Button>
              <TypographyH2 className="shrink-0 truncate text-lg font-bold text-primary sm:text-xl md:hidden">
                B2B Admin
              </TypographyH2>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className={HEADER_ICON_BTN_DESKTOP}
                onClick={() => setSidebarCollapsed((c) => !c)}
                aria-label={sidebarCollapsed ? "Mở sidebar" : "Thu gọn sidebar"}
                title={sidebarCollapsed ? "Mở sidebar" : "Thu gọn sidebar"}
                aria-pressed={!sidebarCollapsed}
              >
                {sidebarCollapsed ? (
                  <PanelLeft aria-hidden className="size-5" />
                ) : (
                  <PanelLeftClose aria-hidden className="size-5" />
                )}
              </Button>
            </div>
            <div className="flex-1" />
            <div className="flex items-center gap-2 sm:gap-3">
              <AdminNotificationBell />
              <DropdownMenu>
                <DropdownMenuTrigger
                  render={
                    <button
                      type="button"
                      className={HEADER_PROFILE_TRIGGER}
                      aria-label="Mở menu tài khoản và tuỳ chỉnh giao diện"
                    />
                  }
                >
                  <div className="hidden min-w-0 text-right sm:block">
                    <p className="max-w-[220px] truncate text-sm font-bold leading-none text-foreground">
                      {displayName}
                    </p>
                    <p
                      className={cn(
                        ADMIN_HEADER_ROLE_LINE_CLASS,
                        "mt-1 max-w-[220px] truncate text-[11px] text-muted-foreground/90",
                      )}
                      title={rolesDisplay}
                    >
                      {rolesDisplay}
                    </p>
                  </div>
                  <div className={HEADER_PROFILE_AVATAR}>
                    {initials(displayName)}
                  </div>
                  <ChevronDown className="hidden size-4 shrink-0 text-muted-foreground transition-transform duration-200 group-aria-expanded:rotate-180 sm:block" />
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-72 p-2">
                  <div className="px-2 py-2">
                    <div className="flex items-center gap-3">
                      <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg border border-primary/20 bg-primary/10 text-sm font-bold text-primary">
                        {initials(displayName)}
                      </div>
                      <div className="min-w-0">
                        <p className="truncate text-sm font-semibold text-foreground">
                          {displayName}
                        </p>
                        <p className="truncate text-xs text-muted-foreground" title={rolesDisplay}>
                          {rolesDisplay}
                        </p>
                      </div>
                    </div>
                  </div>
                  <DropdownMenuSeparator />
                  <DropdownMenuGroup>
                    <DropdownMenuItem
                      className="cursor-pointer rounded-md px-2 py-2"
                      onClick={() => router.push("/profile")}
                    >
                      <UserCircle2 className="size-4 text-muted-foreground" />
                      Hồ sơ và tài khoản
                    </DropdownMenuItem>
                  </DropdownMenuGroup>
                  <DropdownMenuSeparator />
                  <div className="px-2 py-1.5 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                    Giao diện
                  </div>
                  <DropdownMenuRadioGroup
                    value={theme}
                    onValueChange={(value) =>
                      setTheme(value as "light" | "dark" | "system")
                    }
                  >
                    <DropdownMenuRadioItem
                      value="light"
                      className="cursor-pointer rounded-md px-2 py-2"
                    >
                      <Sun className="size-4 text-muted-foreground" />
                      Sáng
                    </DropdownMenuRadioItem>
                    <DropdownMenuRadioItem
                      value="dark"
                      className="cursor-pointer rounded-md px-2 py-2"
                    >
                      <Moon className="size-4 text-muted-foreground" />
                      Tối
                    </DropdownMenuRadioItem>
                    <DropdownMenuRadioItem
                      value="system"
                      className="cursor-pointer rounded-md px-2 py-2"
                    >
                      <Monitor className="size-4 text-muted-foreground" />
                      Theo hệ thống
                    </DropdownMenuRadioItem>
                  </DropdownMenuRadioGroup>
                  <DropdownMenuSeparator />
                  <div className="px-2 py-1.5 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                    Cỡ chữ
                  </div>
                  <DropdownMenuRadioGroup
                    value={size}
                    onValueChange={(value) => setSize(value as "sm" | "base" | "lg")}
                  >
                    <div className="grid grid-cols-3 gap-2 px-2 pb-1 pt-1">
                      <DropdownMenuRadioItem
                        value="sm"
                        className="cursor-pointer justify-center rounded-md border border-border px-2 py-2 font-bold"
                      >
                        S
                      </DropdownMenuRadioItem>
                      <DropdownMenuRadioItem
                        value="base"
                        className="cursor-pointer justify-center rounded-md border border-border px-2 py-2 font-bold"
                      >
                        M
                      </DropdownMenuRadioItem>
                      <DropdownMenuRadioItem
                        value="lg"
                        className="cursor-pointer justify-center rounded-md border border-border px-2 py-2 font-bold"
                      >
                        L
                      </DropdownMenuRadioItem>
                    </div>
                  </DropdownMenuRadioGroup>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </header>
          <main className={ADMIN_MAIN_SCROLL_CLASS}>
            <Page as="div">
              <PageContent className={ADMIN_PAGE_CONTENT_CLASS}>
                {children}
              </PageContent>
            </Page>
          </main>
        </div>
      </div>
      <ScrollToTop />
    </>
  );
}

src/components/admin-table-pagination-fo.content:
"use client";

import { useMemo } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@ui/components/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";

/** Mức page size dùng chung (API thường giới hạn ≤ 200). */
export const ADMIN_TABLE_PAGE_SIZE_OPTIONS = [10, 15, 20, 25, 50] as const;

export type AdminTablePaginationFooterProps = {
  page: number;
  pageSize: number;
  total: number;
  isLoading?: boolean;
  onPageChange: (page: number) => void;
  /** Parent nên `setPage(1)` khi đổi limit (vd. `useEffect` phụ thuộc `pageSize`). */
  onPageSizeChange: (pageSize: number) => void;
  pageSizeOptions?: readonly number[];
  emptySummary: string;
  /** VD: `đơn` → `Hiển thị 1–20 / 100 đơn`; bỏ trống chỉ hiện `… / 100`. */
  itemLabel?: string;
};

export function AdminTablePaginationFooter({
  page,
  pageSize,
  total,
  isLoading = false,
  onPageChange,
  onPageSizeChange,
  pageSizeOptions = ADMIN_TABLE_PAGE_SIZE_OPTIONS,
  emptySummary,
  itemLabel,
}: AdminTablePaginationFooterProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));
  const from = total === 0 ? 0 : (page - 1) * pageSize + 1;
  const to = Math.min(page * pageSize, total);

  const summary =
    total === 0
      ? emptySummary
      : itemLabel
        ? `Hiển thị ${from}–${to} / ${total} ${itemLabel}`
        : `Hiển thị ${from}–${to} / ${total}`;

  const sizeChoices = useMemo(() => {
    const set = new Set<number>([...pageSizeOptions, pageSize]);
    return [...set].sort((a, b) => a - b);
  }, [pageSize, pageSizeOptions]);

  return (
    <>
      <p className="text-sm text-muted-foreground">{summary}</p>
      <div className="flex flex-wrap items-center justify-end gap-2 sm:gap-3">
        <div className="flex items-center gap-2">
          <span className="text-xs font-medium text-muted-foreground whitespace-nowrap">
            Mỗi trang
          </span>
          <Select
            value={String(pageSize)}
            onValueChange={(v) => onPageSizeChange(Number(v))}
            disabled={isLoading}
          >
            <SelectTrigger className="h-9 w-[4.75rem] rounded-lg text-sm tabular-nums">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {sizeChoices.map((n) => (
                <SelectItem key={n} value={String(n)}>
                  {n}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="flex items-center gap-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 rounded-lg"
            disabled={page <= 1 || isLoading}
            onClick={() => onPageChange(Math.max(1, page - 1))}
          >
            <ChevronLeft className="size-4" />
            Trước
          </Button>
          <span className="px-1 text-sm tabular-nums text-muted-foreground sm:px-2">
            Trang {page} / {totalPages}
          </span>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 rounded-lg"
            disabled={page >= totalPages || isLoading}
            onClick={() => onPageChange(Math.min(totalPages, page + 1))}
          >
            Sau
            <ChevronRight className="size-4" />
          </Button>
        </div>
      </div>
    </>
  );
}

src/components/dashboard-charts.tsx.content:
"use client";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";
import { Bar, Line, Doughnut } from "react-chartjs-2";
import { Card, CardContent, CardHeader, CardTitle } from "@ui/components/card";
import type {
  DashboardMonthlyItemDto,
  DashboardCategoryItemDto,
  DashboardTopPostDto,
} from "@/types/dashboard";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  Filler,
);

const MONTH_LABELS: Record<string, string> = {
  "01": "Th1", "02": "Th2", "03": "Th3", "04": "Th4",
  "05": "Th5", "06": "Th6", "07": "Th7", "08": "Th8",
  "09": "Th9", "10": "Th10", "11": "Th11", "12": "Th12",
};

function formatMonth(key: string): string {
  const parts = key.split("-");
  const mm = parts[1] ?? "";
  return MONTH_LABELS[mm] ?? key;
}

const CHART_COLORS = {
  blue:   { bg: "rgba(59,130,246,0.15)",  border: "rgba(59,130,246,0.9)" },
  violet: { bg: "rgba(139,92,246,0.15)",  border: "rgba(139,92,246,0.9)" },
  rose:   { bg: "rgba(244,63,94,0.15)",   border: "rgba(244,63,94,0.9)" },
  amber:  { bg: "rgba(245,158,11,0.15)",  border: "rgba(245,158,11,0.9)" },
  teal:   { bg: "rgba(20,184,166,0.15)",  border: "rgba(20,184,166,0.9)" },
  slate:  { bg: "rgba(100,116,139,0.15)", border: "rgba(100,116,139,0.9)" },
};

const DOUGHNUT_COLORS = [
  "rgba(59,130,246,0.85)",
  "rgba(139,92,246,0.85)",
  "rgba(244,63,94,0.85)",
  "rgba(245,158,11,0.85)",
  "rgba(20,184,166,0.85)",
  "rgba(100,116,139,0.85)",
  "rgba(251,146,60,0.85)",
  "rgba(52,211,153,0.85)",
];

const BASE_OPTIONS = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { display: false },
    tooltip: { mode: "index" as const, intersect: false },
  },
  scales: {
    x: {
      grid: { display: false },
      ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
    },
    y: {
      grid: { color: "rgba(100,116,139,0.08)" },
      ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
      beginAtZero: true,
    },
  },
};

export function MonthlyLineChart({ data }: { data: DashboardMonthlyItemDto[] }) {
  const labels = data.map((d) => formatMonth(d.month));

  const chartData = {
    labels,
    datasets: [
      {
        label: "Bài viết",
        data: data.map((d) => d.posts),
        borderColor: CHART_COLORS.blue.border,
        backgroundColor: CHART_COLORS.blue.bg,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointHoverRadius: 5,
      },
      {
        label: "Tài khoản",
        data: data.map((d) => d.users),
        borderColor: CHART_COLORS.violet.border,
        backgroundColor: CHART_COLORS.violet.bg,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointHoverRadius: 5,
      },
      {
        label: "Liên hệ",
        data: data.map((d) => d.contactRequests),
        borderColor: CHART_COLORS.rose.border,
        backgroundColor: CHART_COLORS.rose.bg,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointHoverRadius: 5,
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Hoạt động theo tháng (12 tháng gần nhất)</CardTitle>
        <div className="flex flex-wrap gap-3 pt-1">
          {chartData.datasets.map((ds) => (
            <span key={ds.label} className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <span className="inline-block size-2.5 rounded-full" style={{ background: ds.borderColor }} />
              {ds.label}
            </span>
          ))}
        </div>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          <Line
            data={chartData}
            options={{
              ...BASE_OPTIONS,
              plugins: {
                ...BASE_OPTIONS.plugins,
                legend: { display: false },
                tooltip: { mode: "index", intersect: false },
              },
            }}
          />
        </div>
      </CardContent>
    </Card>
  );
}

export function MonthlyBarChart({ data }: { data: DashboardMonthlyItemDto[] }) {
  const labels = data.map((d) => formatMonth(d.month));

  const chartData = {
    labels,
    datasets: [
      {
        label: "Bài viết",
        data: data.map((d) => d.posts),
        backgroundColor: CHART_COLORS.blue.border,
        borderRadius: 4,
        barPercentage: 0.6,
      },
      {
        label: "Tài khoản mới",
        data: data.map((d) => d.users),
        backgroundColor: CHART_COLORS.violet.border,
        borderRadius: 4,
        barPercentage: 0.6,
      },
      {
        label: "Liên hệ",
        data: data.map((d) => d.contactRequests),
        backgroundColor: CHART_COLORS.rose.border,
        borderRadius: 4,
        barPercentage: 0.6,
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Bài viết & Tài khoản theo tháng</CardTitle>
        <div className="flex flex-wrap gap-3 pt-1">
          {chartData.datasets.map((ds) => (
            <span key={ds.label} className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <span className="inline-block size-2.5 rounded-full" style={{ background: ds.backgroundColor as string }} />
              {ds.label}
            </span>
          ))}
        </div>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          <Bar data={chartData} options={BASE_OPTIONS} />
        </div>
      </CardContent>
    </Card>
  );
}

function flattenCategories(items: DashboardCategoryItemDto[]): { name: string; count: number }[] {
  const result: { name: string; count: number }[] = [];
  for (const item of items) {
    if (item.count > 0) {
      result.push({ name: item.name, count: item.count });
    }
    if (item.children?.length) {
      result.push(...flattenCategories(item.children));
    }
  }
  return result.sort((a, b) => b.count - a.count).slice(0, 8);
}

export function CategoryDoughnutChart({ data }: { data: DashboardCategoryItemDto[] }) {
  const flat = flattenCategories(data);

  if (!flat.length) {
    return (
      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-base font-semibold">Phân bố bài viết theo danh mục</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-muted-foreground">Chưa có dữ liệu danh mục.</p>
        </CardContent>
      </Card>
    );
  }

  const chartData = {
    labels: flat.map((d) => d.name),
    datasets: [
      {
        data: flat.map((d) => d.count),
        backgroundColor: DOUGHNUT_COLORS,
        borderWidth: 2,
        borderColor: "transparent",
        hoverBorderColor: "rgba(255,255,255,0.6)",
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Phân bố bài viết theo danh mục</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
          <div className="mx-auto h-52 w-52 shrink-0">
            <Doughnut
              data={chartData}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                cutout: "62%",
                plugins: {
                  legend: { display: false },
                  tooltip: {
                    callbacks: {
                      label: (ctx) => ` ${ctx.label}: ${ctx.parsed} bài`,
                    },
                  },
                },
              }}
            />
          </div>
          <ul className="min-w-0 flex-1 space-y-1.5">
            {flat.map((item, i) => (
              <li key={item.name} className="flex items-center gap-2 text-sm">
                <span
                  className="inline-block size-2.5 shrink-0 rounded-full"
                  style={{ background: DOUGHNUT_COLORS[i % DOUGHNUT_COLORS.length] }}
                />
                <span className="min-w-0 flex-1 truncate text-muted-foreground">{item.name}</span>
                <span className="shrink-0 font-semibold tabular-nums">{item.count}</span>
              </li>
            ))}
          </ul>
        </div>
      </CardContent>
    </Card>
  );
}

export function TopPostsChart({ data }: { data: DashboardTopPostDto[] }) {
  if (!data.length) return null;

  const top = data.slice(0, 8);
  const chartData = {
    labels: top.map((p) => p.title.length > 30 ? p.title.slice(0, 30) + "…" : p.title),
    datasets: [
      {
        label: "Bình luận",
        data: top.map((p) => p.comments),
        backgroundColor: CHART_COLORS.teal.border,
        borderRadius: 4,
        barPercentage: 0.65,
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Top bài viết nhiều bình luận nhất</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          <Bar
            data={chartData}
            options={{
              ...BASE_OPTIONS,
              indexAxis: "y" as const,
              scales: {
                x: {
                  grid: { color: "rgba(100,116,139,0.08)" },
                  ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
                  beginAtZero: true,
                },
                y: {
                  grid: { display: false },
                  ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
                },
              },
            }}
          />
        </div>
      </CardContent>
    </Card>
  );
}

src/components/scroll-to-top.tsx.content:
"use client";

import { useEffect, useState } from "react";
import { ArrowUp } from "lucide-react";
import { Button } from "@ui/components/button";
import { cn } from "@ui/lib/utils";

const VISIBILITY_THRESHOLD = 300;

function getScrollY(): number {
  return window.scrollY ?? window.pageYOffset ?? document.documentElement.scrollTop ?? document.body.scrollTop ?? 0;
}

export function ScrollToTop() {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const main = document.querySelector<HTMLElement>("main[class*='overflow-y-auto']");

    const checkScroll = () => {
      const scrollY = getScrollY();
      const mainScrollTop = main?.scrollTop ?? 0;
      setVisible(Math.max(scrollY, mainScrollTop) > VISIBILITY_THRESHOLD);
    };

    window.addEventListener("scroll", checkScroll, { passive: true });
    if (main) main.addEventListener("scroll", checkScroll, { passive: true });

    // initial check after mount
    const raf = requestAnimationFrame(checkScroll);

    return () => {
      window.removeEventListener("scroll", checkScroll);
      if (main) main.removeEventListener("scroll", checkScroll);
      cancelAnimationFrame(raf);
    };
  }, []);

  const scrollToTop = () => {
    const main = document.querySelector<HTMLElement>("main[class*='overflow-y-auto']");
    if (main && main.scrollTop > 0) {
      main.scrollTo({ top: 0, behavior: "smooth" });
    } else {
      window.scrollTo({ top: 0, behavior: "smooth" });
    }
  };

  return (
    <Button
      variant="secondary"
      size="icon"
      aria-label="Cuộn lên đầu trang"
      onClick={scrollToTop}
      className={cn(
        "fixed bottom-6 right-6 z-50 flex size-10 items-center justify-center rounded-full bg-secondary text-secondary-foreground shadow-lg transition-all duration-300 hover:bg-secondary/90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        visible
          ? "translate-y-0 opacity-100"
          : "pointer-events-none translate-y-2 opacity-0",
      )}
    >
      <ArrowUp className="size-5 text-secondary-foreground" />
    </Button>
  );
}

src/components/sidebar.tsx.content:
"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  ShieldCheck,
  Database,
  LayoutDashboard,
  Tags,
  FolderOpen,
  FileText,
  Users,
  ChevronDown,
  FolderTree,
  ChevronsUpDown,
  LogOut,
  Headset,
  GraduationCap,
  UserCheck,
  BookOpen,
  type LucideIcon,
} from "lucide-react";
import { Button } from "@ui/components/button";
import { cn } from "@ui/lib/utils";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@ui/components/collapsible";
import {
  canUserAccess,
  PERMISSION_CODES,
  type PermissionCode,
} from "@workspace/api-client";
import { useAuth } from "@/providers/auth-provider";
import type { AuthUser } from "@/lib/api";

type MenuLeaf = {
  href: string;
  label: string;
  icon: LucideIcon;
  permission: PermissionCode | null;
  anyPermission?: PermissionCode[];
  /** Chỉ hiển thị với role cụ thể này (khớp role.name). */
  roleGuard?: string;
  /** Chỉ hiển thị với super_admin hoặc admin — ẩn với parent và các role không phải staff. */
  adminOnly?: boolean;
};

type MenuTreeItem =
  | ({ type: "leaf" } & MenuLeaf)
  | {
    type: "group";
    label: string;
    icon: LucideIcon;
    children: MenuLeaf[];
  };

const menuTree: MenuTreeItem[] = [
  {
    type: "leaf",
    href: "/",
    label: "Tổng quan",
    icon: LayoutDashboard,
    permission: null,
  },
  {
    type: "leaf",
    href: "/my-students",
    label: "Con tôi",
    icon: GraduationCap,
    permission: null,
    roleGuard: "parent",
  },
  {
    type: "group",
    label: "Truyền thông",
    icon: FolderTree,
    children: [
      {
        href: "/guides",
        label: "Hướng dẫn sử dụng",
        icon: BookOpen,
        permission: PERMISSION_CODES.PAGE_CONTENTS_VIEW,
        adminOnly: true,
      },
      {
        href: "/posts",
        label: "Bài viết",
        icon: FileText,
        permission: null,
        adminOnly: true,
      },
      {
        href: "/categories",
        label: "Danh mục",
        icon: FolderOpen,
        permission: null,
        adminOnly: true,
      },
      {
        href: "/tags",
        label: "Thẻ",
        icon: Tags,
        permission: null,
        anyPermission: [
          PERMISSION_CODES.TAGS_VIEW,
          PERMISSION_CODES.TAGS_MANAGE,
        ],
        adminOnly: true,
      },
    ],
  },
  {
    type: "group",
    label: "Hệ thống",
    icon: Database,
    children: [
      {
        href: "/staff",
        label: "Nhân sự",
        icon: Users,
        permission: null,
        anyPermission: [PERMISSION_CODES.USERS_MANAGE],
        adminOnly: true,
      },
      {
        href: "/rbac",
        label: "Phân quyền",
        icon: ShieldCheck,
        permission: PERMISSION_CODES.RBAC_READ,
        adminOnly: true,
      },
      {
        href: "/data",
        label: "Sao lưu dữ liệu",
        icon: Database,
        permission: PERMISSION_CODES.DATA_MAINTENANCE,
        adminOnly: true,
      },
      {
        href: "/contact-requests",
        label: "Liên hệ hỗ trợ",
        icon: Headset,
        anyPermission: [
          PERMISSION_CODES.CONTACT_REQUESTS_VIEW,
          PERMISSION_CODES.CONTACT_REQUESTS_MANAGE,
          PERMISSION_CODES.CONTACT_REQUESTS_UPDATE,
          PERMISSION_CODES.CONTACT_REQUESTS_ASSIGN,
        ],
        permission: null,
        adminOnly: true,
      },
      {
        href: "/parent-students",
        label: "Duyệt học sinh",
        icon: UserCheck,
        permission: null,
        anyPermission: [PERMISSION_CODES.USERS_MANAGE],
        adminOnly: true,
      },
    ],
  },
];

const SUPER_ROLES = ["super_admin", "admin"] as const;

function isSuperUser(user: AuthUser): boolean {
  return user.roles?.some((r) => SUPER_ROLES.includes(r.name as (typeof SUPER_ROLES)[number])) ?? false;
}

function canSeeLeaf(user: AuthUser | null, item: MenuLeaf): boolean {
  if (!user) return false;
  if (isSuperUser(user)) return true;
  // roleGuard: chỉ role cụ thể này mới thấy (ví dụ: "parent" cho /my-students)
  if (item.roleGuard) {
    return user.roles?.some((r) => r.name === item.roleGuard) ?? false;
  }
  // adminOnly: ẩn với tất cả role không phải super_admin/admin
  if (item.adminOnly) return false;
  if (item.anyPermission?.length) {
    return item.anyPermission.some((p) => canUserAccess(user, p));
  }
  if (item.permission === null) return true;
  return canUserAccess(user, item.permission);
}

export function getVisibleMenuItems(user: AuthUser | null): MenuTreeItem[] {
  if (!user) return [];
  return menuTree.reduce<MenuTreeItem[]>((acc, item) => {
    if (item.type === "leaf") {
      if (canSeeLeaf(user, item)) {
        acc.push(item);
      }
      return acc;
    }

    const children = item.children.filter((child) => canSeeLeaf(user, child));
    if (children.length === 0) {
      return acc;
    }
    acc.push({ ...item, children });
    return acc;
  }, []);
}

function displayNameOf(user: AuthUser | null): string {
  return user?.name?.trim() || user?.email || "Người dùng HUB";
}

function roleSummaryOf(user: AuthUser | null): string {
  const labels = (user?.roles ?? [])
    .map((role) => role.displayName || role.name)
    .filter(Boolean);
  if (!labels.length) return "Chưa gán vai trò";
  return labels.join(" · ");
}

function initialsOf(name: string): string {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "HU";
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase();
}

function SidebarLeafLink({
  item,
  isActive,
  collapsed,
  onClick,
  nested = false,
}: {
  item: MenuLeaf;
  isActive: boolean;
  collapsed: boolean;
  onClick?: () => void;
  nested?: boolean;
}) {
  const Icon = item.icon;

  return (
    <Link
      href={item.href}
      title={item.label}
      onClick={onClick}
      className={cn(
        "group relative flex items-center overflow-hidden rounded-lg transition-all duration-200",
        collapsed
          ? "justify-center px-2 py-3"
          : nested
            ? "gap-3 px-3 py-1.5"
            : "gap-3 px-3 py-1.5",
        isActive
          ? nested
            ? "bg-white/10 text-white"
            : "bg-[#3658B7] text-white shadow-[0_10px_24px_rgba(12,22,63,0.28)]"
          : "text-white/88 hover:bg-white/8 hover:text-white",
      )}
    >
      {isActive && !collapsed ? (
        <span
          className={cn(
            "absolute left-0 rounded-r-full",
            nested
              ? "inset-y-2.5 w-px bg-white/35"
              : "inset-y-2 w-1 bg-white/85",
          )}
        />
      ) : null}
      <span
        className={cn(
          "flex shrink-0 items-center justify-center rounded-lg transition-all duration-200",
          collapsed ? "size-9" : nested ? "size-8" : "size-8",
          isActive
            ? nested
              ? "bg-white/10 text-white"
              : "bg-white/12 text-white"
            : "text-white/78 group-hover:text-white",
        )}
      >
        <Icon
          className={cn(
            "shrink-0 transition-transform duration-200 group-hover:scale-105",
            nested ? "size-[1.05rem]" : "size-[1.1rem]",
          )}
        />
      </span>
      {!collapsed && (
        <span
          className={cn(
            "min-w-0 flex-1 truncate",
            nested ? "text-[0.98rem] font-medium" : "text-[1.02rem] font-semibold",
          )}
        >
          {item.label}
        </span>
      )}
    </Link>
  );
}

function isLeafActive(pathname: string, href: string): boolean {
  return pathname === href;
}

function isGroupActive(pathname: string, items: MenuLeaf[]): boolean {
  return items.some((item) => isLeafActive(pathname, item.href));
}

function getFlatVisibleLeaves(items: MenuTreeItem[]): MenuLeaf[] {
  return items.flatMap((item) =>
    item.type === "leaf" ? [item] : item.children,
  );
}

function getLegacyVisibleItems(user: AuthUser | null): MenuLeaf[] {
  const visible = getVisibleMenuItems(user);
  return getFlatVisibleLeaves(visible);
}

function LegacyCollapsedNav({
  visible,
  pathname,
  onLinkClick,
}: {
  visible: MenuLeaf[];
  pathname: string;
  onLinkClick?: () => void;
}) {
  return (
    <>
      {visible.map((item) => (
        <SidebarLeafLink
          key={item.href}
          item={item}
          isActive={isLeafActive(pathname, item.href)}
          collapsed
          onClick={onLinkClick}
        />
      ))}
    </>
  );
}

function TreeNav({
  visible,
  pathname,
  onLinkClick,
}: {
  visible: MenuTreeItem[];
  pathname: string;
  onLinkClick?: () => void;
}) {
  const [openGroups, setOpenGroups] = useState<Record<string, boolean>>({});

  useEffect(() => {
    setOpenGroups((prev) => {
      const next: Record<string, boolean> = {};

      for (const item of visible) {
        if (item.type !== "group") continue;
        const isActive = isGroupActive(pathname, item.children);
        next[item.label] = prev[item.label] ?? isActive;
        if (isActive) {
          next[item.label] = true;
        }
      }

      return next;
    });
  }, [pathname, visible]);

  return (
    <>
      {visible.map((item) => {
        if (item.type === "leaf") {
          return (
            <SidebarLeafLink
              key={item.href}
              item={item}
              isActive={isLeafActive(pathname, item.href)}
              collapsed={false}
              onClick={onLinkClick}
            />
          );
        }

        const groupActive = isGroupActive(pathname, item.children);
        return (
          <Collapsible
            key={item.label}
            open={openGroups[item.label] ?? groupActive}
            onOpenChange={(open) =>
              setOpenGroups((prev) => ({ ...prev, [item.label]: open }))
            }
            className="rounded-lg"
          >
            <CollapsibleTrigger
              className={cn(
                "group flex w-full items-center gap-3 rounded-lg px-3 py-1.5 text-left transition-all duration-200",
                groupActive
                  ? "bg-white/6 text-white mb-1"
                  : "text-white/90 hover:bg-white/7 hover:text-white",
              )}
            >
              <span
                className={cn(
                  "flex size-8 shrink-0 items-center justify-center rounded-lg",
                  groupActive
                    ? "bg-white/10 text-white"
                    : "text-white/78 group-hover:text-white",
                )}
              >
                <item.icon className="size-[1.1rem]" />
              </span>
              <div className="min-w-0 flex-1">
                <p className="truncate text-[1.02rem] font-semibold">{item.label}</p>
                <p className="truncate text-[11px] text-white/55">
                  {item.children.length} mục
                </p>
              </div>
              <ChevronDown className="size-4 shrink-0 text-white/55 transition-transform duration-200" />
            </CollapsibleTrigger>
            <CollapsibleContent className="px-2 pb-1">
              <div className="ml-4 space-y-1 border-l border-white/12 pl-3">
                {item.children.map((child) => (
                  <SidebarLeafLink
                    key={child.href}
                    item={child}
                    isActive={isLeafActive(pathname, child.href)}
                    collapsed={false}
                    nested
                    onClick={onLinkClick}
                  />
                ))}
              </div>
            </CollapsibleContent>
          </Collapsible>
        );
      })}
    </>
  );
}

export function SidebarNavLinks({
  collapsed,
  onLinkClick,
  className,
}: {
  collapsed: boolean;
  onLinkClick?: () => void;
  className?: string;
}) {
  const pathname = usePathname();
  const { user } = useAuth();
  const visible = getVisibleMenuItems(user);
  const collapsedVisible = getLegacyVisibleItems(user);

  return (
    <nav
      className={cn(
        "flex-1 overflow-y-auto",
        collapsed ? "p-2" : "p-4",
        className,
      )}
    >
      {!collapsed && (
        <div className="px-3 pb-2 pt-1 text-[11px] font-semibold uppercase tracking-[0.16em] text-white/52">
          Platform
        </div>
      )}
      <div className={cn("space-y-1.5", collapsed ? "" : "space-y-2")}>
        {collapsed ? (
          <LegacyCollapsedNav
            visible={collapsedVisible}
            pathname={pathname}
            onLinkClick={onLinkClick}
          />
        ) : (
          <TreeNav visible={visible} pathname={pathname} onLinkClick={onLinkClick} />
        )}
      </div>
    </nav>
  );
}

/** Menu dạng drawer cho màn hình nhỏ (Sheet). */
export function MobileSidebarPanel({ onNavigate }: { onNavigate: () => void }) {
  const { user, logout } = useAuth();
