export function proxy(request: NextRequest) {
  if (process.env.NODE_ENV === "development") {
    const { pathname, search } = request.nextUrl;
    console.log(
      `[backend] ${request.method} ${pathname}${search ? search : ""}`,
    );
  }

  return NextResponse.next();
}

